import { execSync } from 'child_process';
import { AssistantStrategy } from '../strategies';
import grep from './grep';

/* Generated by @n1k1t/unit-generator */
it('should call execSync with default arguments when no optional parameters are provided', async () => {
  const mockExecSync = jest.spyOn(require('child_process'), 'execSync').mockReturnValue('match');
  const strategy = { source: { ignore: [] } } as unknown as AssistantStrategy;
  const tool = grep(strategy);

  await tool.execute?.({ pattern: 'test-pattern' }, {} as any);

  expect(mockExecSync).toHaveBeenCalledWith('grep -rnE "test-pattern" .', { encoding: 'utf-8' });

  mockExecSync.mockRestore();
});

