it('parses grep output and respects ignore patterns', async () => {
  const strategy: AssistantStrategy = {
    source: {
      ignore: ['node_modules/**', 'dist/**'],
    },
  } as unknown as AssistantStrategy;

  const mockedOutput = 'src/file.ts:10: matched\nsrc/file.ts-11- context\n';
  const spy = jest.spyOn(require('child_process'), 'execSync').mockReturnValue(mockedOutput);

  const result = await grep(strategy).execute?.({ pattern: 'foo', path: '.' }, {} as any);

  expect((result as any).output?.[0].content).toBe('10: matched\n11: context');
  spy.mockRestore();
});

